using System.Text.Json;
using KspNavComputer.Core.Bodies;
using KspNavComputer.Core.Transfer;

namespace KspNavComputer.Core.Tests;

/// <summary>
/// Cross-validates TransferComputer.ComputeRoundTrip against pre-computed
/// reference values generated by alexmoon's Launch Window Planner (LWP).
///
/// Reference data: tests/Core/Data/reference-round-trips.json
/// Generator script: scripts/generate-round-trip-references.js
///
/// Each reference case is the sum of two independent LWP one-way transfers:
///   outbound (origin → dest) + return (dest → origin).
/// Tolerance: ±1 % per leg on total Δv (same as one-way reference tests).
/// </summary>
public sealed class ReferenceRoundTripTests
{
    private sealed record ReferenceCase(
        string Description,
        string Origin,
        string Destination,
        double DepartureUT,
        double OutboundTimeOfFlight,
        double StayDuration,
        double ReturnTimeOfFlight,
        double ParkingOrbitAltitude,
        double DestinationOrbitAltitude,
        double OutboundEjectionDeltaV,
        double OutboundInsertionDeltaV,
        double OutboundTotalDeltaV,
        double ReturnEjectionDeltaV,
        double ReturnInsertionDeltaV,
        double ReturnTotalDeltaV,
        double TotalDeltaV
    );

    private static IReadOnlyList<ReferenceCase> LoadCases()
    {
        var dataPath = Path.Combine(
            AppContext.BaseDirectory,
            "Data",
            "reference-round-trips.json"
        );
        var json    = File.ReadAllText(dataPath);
        var options = new JsonSerializerOptions { PropertyNameCaseInsensitive = true };
        return JsonSerializer.Deserialize<List<ReferenceCase>>(json, options)!;
    }

    public static IEnumerable<object[]> ReferenceCaseData()
    {
        foreach (var c in LoadCases())
            yield return [
                c.Description,
                c.Origin, c.Destination,
                c.DepartureUT, c.OutboundTimeOfFlight, c.StayDuration, c.ReturnTimeOfFlight,
                c.ParkingOrbitAltitude, c.DestinationOrbitAltitude,
                c.OutboundEjectionDeltaV, c.OutboundInsertionDeltaV, c.OutboundTotalDeltaV,
                c.ReturnEjectionDeltaV,   c.ReturnInsertionDeltaV,   c.ReturnTotalDeltaV,
                c.TotalDeltaV
            ];
    }

    [Theory]
    [MemberData(nameof(ReferenceCaseData))]
    public void RoundTrip_MatchesLwpReference_WithinOnePct(
        string description,
        string origin, string destination,
        double departureUT, double outboundTof, double stayDuration, double returnTof,
        double parkAlt, double destAlt,
        double expOutEject, double expOutInsert, double expOutTotal,
        double expRetEject, double expRetInsert, double expRetTotal,
        double expTotal)
    {
        _ = description;

        var parameters = new RoundTripParameters(
            Origin:               BodyDatabase.All[origin],
            Destination:          BodyDatabase.All[destination],
            DepartureUT:          departureUT,
            OutboundTimeOfFlight: outboundTof,
            StayDuration:         stayDuration,
            ReturnTimeOfFlight:   returnTof,
            OriginOrbit:          new ParkingOrbit(Altitude: parkAlt),
            DestinationOrbit:     new ParkingOrbit(Altitude: destAlt)
        );

        var result = TransferComputer.ComputeRoundTrip(parameters);

        const double tol = 0.01; // 1 %

        // Outbound leg
        AssertWithinPct(expOutEject,  result.Outbound.EjectionDeltaV,  tol, $"{description} outbound ejection");
        AssertWithinPct(expOutInsert, result.Outbound.InsertionDeltaV, tol, $"{description} outbound insertion");
        AssertWithinPct(expOutTotal,  result.Outbound.TotalDeltaV,     tol, $"{description} outbound total");

        // Return leg
        AssertWithinPct(expRetEject,  result.Return.EjectionDeltaV,    tol, $"{description} return ejection");
        AssertWithinPct(expRetInsert, result.Return.InsertionDeltaV,   tol, $"{description} return insertion");
        AssertWithinPct(expRetTotal,  result.Return.TotalDeltaV,       tol, $"{description} return total");

        // Mission total
        AssertWithinPct(expTotal, result.TotalDeltaV, tol, $"{description} mission total");
    }

    private static void AssertWithinPct(double expected, double actual, double pct, string label)
    {
        double relErr = Math.Abs(actual - expected) / expected;
        Assert.True(
            relErr <= pct,
            $"{label}: expected {expected:F2} m/s, got {actual:F2} m/s " +
            $"(relative error {relErr * 100:F3} % > tolerance {pct * 100:F1} %)");
    }
}
